import{_ as s,C as n,c as i,o as t,a3 as e,b as E,w as o,a as p,G as l,a4 as c}from"./chunks/framework.CswI76e5.js";const C=JSON.parse('{"title":"2.1 プログラミングの基礎知識","description":"","frontmatter":{},"headers":[],"relativePath":"cpp/chapter-2/1.md","filePath":"cpp/chapter-2/1.md","lastUpdated":1778209237000}'),_={name:"cpp/chapter-2/1.md"};function d(A,a,u,h,m,B){const r=n("Mermaid");return t(),i("div",null,[a[1]||(a[1]=e('<h1 id="_2-1-プログラミングの基礎知識" tabindex="-1">2.1 プログラミングの基礎知識 <a class="header-anchor" href="#_2-1-プログラミングの基礎知識" aria-label="Permalink to &quot;2.1 プログラミングの基礎知識&quot;">​</a></h1><p>まずは「プログラミング」とはなにか、という半ばご高説を垂れるような話から始めよう。</p><h2 id="_2-1-1-プログラミングとは" tabindex="-1">2.1.1 プログラミングとは <a class="header-anchor" href="#_2-1-1-プログラミングとは" aria-label="Permalink to &quot;2.1.1 プログラミングとは&quot;">​</a></h2><p>プログラミングとは「コンピューターにどのような動作をさせるかを予め指示する行為」である。ここでいうコンピューターは、我々が今使っているノートパソコンだけではなく、TSUBAMEのようなサーバーなどや、電子レンジ等の中に入っている制御装置（残り何分かを表示したり、どのボタンを押したかで動作を変えたり）も指し示す。</p><p>コンピューターは、私達よりもずっと速く、そして正確に計算することができるが、人間の言語を理解できない。人間の言語は思っているよりも曖昧であり、一方コンピューターはすべて0と1の2進数によって動作し厳密に指示を与えなければならない。 そのコンピューターが理解できる形で指示するために、プログラミングをするのである。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>プログラミング&quot;言語&quot;というものは様々あって、「C++」はその中の一つである。他にも「Python」「JavaScript」「C#」など言語がある中で今回C++を選んでいる理由は2つ。</p><ol><li>大抵の言語はC++の（もっと言えばCの）派生だから。C++で一通りプログラミングを勉強してしまえば、C#など他の言語にすぐに乗り換えられるから。</li><li>C++が比較的コンピューター寄りだから。</li></ol></div><h2 id="_2-1-2-コンパイルとは" tabindex="-1">2.1.2 コンパイルとは <a class="header-anchor" href="#_2-1-2-コンパイルとは" aria-label="Permalink to &quot;2.1.2 コンパイルとは&quot;">​</a></h2><p>先述した通り、コンピューターは2進数によって動作する。よって与える命令も2進数でできるだけコンピューターでの動作に特化した形式になっている（「機械語」の形になっている）のだが、これを人間が読むことは困難である。よって比較的わかりやすく、かつ機械語に変換できる言語としてプログラミング言語を用いる。</p><p>プログラミング言語によって記述されたプログラムは、コンピューターが直接命令として理解できる形ではない。そのため、コンピューターが読める形に変換しなければならない。 この操作を「コンパイル」と呼び、コンパイルによって生成された01からなるデータ(バイナリ)をコンピューターは読み込む。</p>',9)),(t(),E(c,null,{default:o(()=>[l(r,{id:"mermaid-41",class:"mermaid",graph:"flowchart%20LR%0Ath(%22%E4%BA%BA%E9%96%93%E3%81%AE%E8%80%83%E3%81%88%E3%81%A6%E3%81%84%E3%82%8B%E3%81%93%E3%81%A8%22)%20--%3E%20%7C%22%E3%83%97%E3%83%AD%E3%82%B0%E3%83%A9%E3%83%9F%E3%83%B3%E3%82%B0%22%7C%20pg(%22%E3%83%97%E3%83%AD%E3%82%B0%E3%83%A9%E3%83%9F%E3%83%B3%E3%82%B0%E8%A8%80%E8%AA%9E%22)%0Apg%20--%3E%20%7C%22%E3%82%B3%E3%83%B3%E3%83%91%E3%82%A4%E3%83%AB%22%7C%20mc(%22%E3%83%90%E3%82%A4%E3%83%8A%E3%83%AA(%E6%A9%9F%E6%A2%B0%E8%AA%9E)%22)%0Amc%20--%3E%20%7C%22%E5%91%BD%E4%BB%A4%22%7C%20cp(%22%E3%82%B3%E3%83%B3%E3%83%94%E3%83%A5%E3%83%BC%E3%82%BF%E3%83%BC%22)%0A"})]),fallback:o(()=>a[0]||(a[0]=[p(" Loading... ")])),_:1})),a[2]||(a[2]=e('<h2 id="_2-1-3-osとは" tabindex="-1">2.1.3 OSとは <a class="header-anchor" href="#_2-1-3-osとは" aria-label="Permalink to &quot;2.1.3 OSとは&quot;">​</a></h2><p>OSは、Operating Systemの略。この講習会中では、上のグラフの「機械語」を読み取って、コンピューターを実際に動かす部分を担当している。他にも、ユーザーの様々な操作（画面上のポインタを動かす、キーボードの入力を受け付けて適切に情報を分配する、HDD/SDDを操作する、などなど…）とコンピューターをつなぐ役割を果たす。</p><p>Windows / Mac（Macintosh）は主要なOSである。受講者の大半はこのどちらかのOSを使用しているだろう。</p><p>他にも、開発においてよく使用されるOSとして<strong>Linux</strong>が存在し、いくつかの班ではLinuxを用いて作業する。</p><p>Mac OSはLinuxに「近い」（初学者である間はLinuxの一種だと思っても良い）が、WindowsはLinuxとは大きく異なるOS なので、Windowsユーザーはよく<strong>WSL</strong>を使用する。 WSLは<strong>Windows Subsystem for Linux</strong>の略。コンピューターの内部に、仮想的なLinuxのコンピューターが入ってると考えると良い。</p><p>Ubuntuは、Linuxディストリビューションの一つで、Linuxのカスタマイズみたいなものである。</p>',6))])}const x=s(_,[["render",d]]);export{C as __pageData,x as default};
